    graph_copy = graph_data.copy()

    target_domain_name = 'ju1.s3.dom'
    new_switch_name = 'new_EK_PACKET_SWITCH_45'

    # Helper to get nodes by 'name' attribute
    def find_nodes_by_name(g, name):
        return [n for n, d in g.nodes(data=True) if d.get('name') == name]

    # Ensure the target domain node exists; if not, create it as an EK_CONTROL_DOMAIN
    domain_nodes = find_nodes_by_name(graph_copy, target_domain_name)
    if not domain_nodes:
        domain_node_id = target_domain_name
        graph_copy.add_node(domain_node_id, name=target_domain_name, type=['EK_CONTROL_DOMAIN'])
        domain_nodes = [domain_node_id]

    # Ensure the new packet switch node exists (with correct type)
    existing_switch_nodes = find_nodes_by_name(graph_copy, new_switch_name)
    if existing_switch_nodes:
        new_switch_id = existing_switch_nodes[0]
        # Ensure 'type' includes EK_PACKET_SWITCH
        node_type = graph_copy.nodes[new_switch_id].get('type', [])
        if 'EK_PACKET_SWITCH' not in node_type:
            # Ensure type is a list
            if not isinstance(node_type, list):
                node_type = [node_type] if node_type else []
            node_type.append('EK_PACKET_SWITCH')
            graph_copy.nodes[new_switch_id]['type'] = node_type
        # Ensure 'name' attribute is set correctly
        if graph_copy.nodes[new_switch_id].get('name') != new_switch_name:
            graph_copy.nodes[new_switch_id]['name'] = new_switch_name
    else:
        new_switch_id = new_switch_name
        graph_copy.add_node(new_switch_id, name=new_switch_name, type=['EK_PACKET_SWITCH'])

    # Add RK_CONTAINS edge from the domain node(s) to the new switch
    for dn in domain_nodes:
        if graph_copy.has_edge(dn, new_switch_id):
            # Update the edge type to RK_CONTAINS
            graph_copy[dn][new_switch_id]['type'] = 'RK_CONTAINS'
        else:
            graph_copy.add_edge(dn, new_switch_id, type='RK_CONTAINS')

    # Count EK_PACKET_SWITCH directly contained in the target domain (via RK_CONTAINS edges)
    count_switches = 0
    for dn in domain_nodes:
        for succ in graph_copy.successors(dn):
            edge_data = graph_copy.get_edge_data(dn, succ) or {}
            if edge_data.get('type') == 'RK_CONTAINS':
                succ_type = graph_copy.nodes[succ].get('type', [])
                if isinstance(succ_type, list) and 'EK_PACKET_SWITCH' in succ_type:
                    count_switches += 1

    # Prepare return object
    try:
        graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
    except Exception:
        # Fallback: if nx is not available in scope, provide a minimal structure
        # This ensures the function returns something sensible even without nx import.
        graph_json = {
            "directed": True,
            "multigraph": False,
            "graph": {},
            "nodes": [{"id": n, **(graph_copy.nodes[n] if isinstance(graph_copy.nodes[n], dict) else {})} for n in graph_copy.nodes()],
            "links": [{"source": u, "target": v, **(graph_copy.get_edge_data(u, v) or {})} for u, v in graph_copy.edges()]
        }

    return_object = {
        "type": "text",
        "data": str(count_switches),
        "updated_graph": graph_json
    }
    return return_object
